long long getphi(long long x, int s) &#123;
    if(s == 0)  return x;
    if(s &lt;= M)  return phi[x % sz[s]][s] + (x / sz[s]) * phi[sz[s]][s];
    if(x &lt;= prime[s]*prime[s])   return pi[x] - s + 1;
    if(x &lt;= prime[s]*prime[s]*prime[s] &amp;&amp; x &lt; N) &#123;
        int s2x = pi[sqrt2(x)];
