    tree[i].r = r;
    tree[i].mlz = 1;
    if(l ==r ) &#123;tree[i].sum = input[l]%p; return;&#125;
    long long mid = (l+r)>>1;
    build(i&lt;&lt;1, l, mid);
    build(i&lt;&lt;1|1, mid+1, r);
    tree[i].sum = (tree[i&lt;&lt;1].sum+tree[i&lt;&lt;1|1].sum)%p;
    return;
&#125;
inline void pushdown(long long i) &#123;
